@* Displays a single task card with move-left/move-right buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text text-muted small mb-1">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center mb-1">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex justify-content-between">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeftAsync">
                    &larr; Move Left
                </button>
            }
            else
            {
                <span></span>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRightAsync">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async System.Threading.Tasks.Task OnMoveLeftAsync() => await OnMoveLeft.InvokeAsync();
    private async System.Threading.Tasks.Task OnMoveRightAsync() => await OnMoveRight.InvokeAsync();
}

@* Inline form to create a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title"
                   @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                   @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm" @onclick="SaveAsync" disabled="@isSaving">
                @(isSaving ? "Saving…" : "Save")
            </button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="Cancel" disabled="@isSaving">
                Cancel
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    private async Task SaveAsync()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        isSaving = true;
        try
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@* A single Kanban column with header, task cards, and optional add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="() => OnMoveTask.InvokeAsync((task.Id, -1))"
                          OnMoveRight="() => OnMoveTask.InvokeAsync((task.Id, 1))" />
            }

            @if (showAddForm)
            {
                <AddTaskForm OnSave="HandleSaveAsync" OnCancel="() => showAddForm = false" />
            }
        </div>
        <div class="card-footer p-2">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showAddForm = true"
                    disabled="@showAddForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, int Direction)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnAddTask { get; set; }

    private bool showAddForm;

    private async Task HandleSaveAsync((string Title, string Assignee, string Priority, DateTime DueDate) formData)
    {
        await OnAddTask.InvokeAsync((formData.Title, formData.Assignee, formData.Priority, formData.DueDate, ColumnName));
        showAddForm = false;
    }
}

@* Summary statistics bar showing task counts and overdue count *@

<div class="row g-2 mb-3">
    <div class="col"><div class="card text-center p-2"><small class="text-muted">Total</small><div class="fw-bold">@Tasks.Count</div></div></div>
    <div class="col"><div class="card text-center p-2"><small class="text-muted">To Do</small><div class="fw-bold">@Tasks.Count(t => t.Status == "To Do")</div></div></div>
    <div class="col"><div class="card text-center p-2"><small class="text-muted">In Progress</small><div class="fw-bold">@Tasks.Count(t => t.Status == "In Progress")</div></div></div>
    <div class="col"><div class="card text-center p-2"><small class="text-muted">Done</small><div class="fw-bold">@Tasks.Count(t => t.Status == "Done")</div></div></div>
    <div class="col"><div class="card text-center p-2"><small class="text-muted">Overdue</small><div class="fw-bold text-danger">@Tasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done")</div></div></div>
</div>

@code {
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search tasks by title…"
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? string.Empty;
        await SearchTermChanged.InvokeAsync(value);
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar @bind-SearchTerm="searchTerm" />

    <div class="row g-3">
        @for (var i = 0; i < columns.Length; i++)
        {
            var column = columns[i];
            var colIndex = i;
            <BoardColumn ColumnName="@column"
                         Tasks="GetFilteredTasks(column)"
                         ShowMoveLeft="colIndex > 0"
                         ShowMoveRight="colIndex < columns.Length - 1"
                         OnMoveTask="args => MoveTaskAsync(args.TaskId, args.Direction)"
                         OnAddTask="AddTaskAsync" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchTerm = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var filtered = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            filtered = filtered.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private async Task MoveTaskAsync(int taskId, int direction)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == taskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(columns, task.Status);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= columns.Length) return;

        var newStatus = columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            // Update local state
            var idx = allTasks.FindIndex(t => t.Id == taskId);
            allTasks[idx] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task AddTaskAsync((string Title, string Assignee, string Priority, DateTime DueDate, string Status) data)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            // CreateTaskAsync returns a task with default status; ensure it matches the column
            if (newTask.Status != data.Status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, data.Status);
                newTask = newTask with { Status = data.Status };
            }
            allTasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

